import { writeOutput } from "./codegen";

const DOCS_URL = "https://www.cronlytic.com/api-documentation";
const PLACEHOLDER_API_KEY =
  "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSafe";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Cronlytic API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:cronlytic",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const cronlyticFirewall = {",
    '  name: "cronlytic",',
    '  description: "Cronlytic API",',
    "  placeholders: {",
    `    CRONLYTIC_API_KEY: "${PLACEHOLDER_API_KEY}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.cronlytic.com",',
    "      auth: {",
    "        headers: {",
    '          "x-api-key": "${{ secrets.CRONLYTIC_API_KEY }}",',
    '          "x-user-id": "${{ vars.CRONLYTIC_USER_ID }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Cronlytic firewall config...");
  const ts = generateTypeScript();
  writeOutput("cronlytic", ts, import.meta.dirname);
}
